def solve(*args, **kwargs):
    """
    Read input data, process it, and output the result. This function is the main entry point of the program.
    """
    if not args or len(args) < 3:
        return -1

    n = args[0]
    k = args[1]
    a = args[2]

    # Check if total slices is less than k (each pupil needs at least 1 slice)
    total_slices = sum(a)
    if total_slices < k:
        return -1

    # Binary search for the maximum possible joy
    left = 1
    right = max(a)
    result = -1

    while left <= right:
        mid = (left + right) // 2
        if can_distribute(n, k, a, mid):
            result = mid
            left = mid + 1
        else:
            right = mid - 1

    return result

def can_distribute(*args, **kwargs):
    """
    Check if we can distribute at least min_slices to all k pupils.
    For each tangerine with a_i slices, we can get floor(a_i / min_slices) parts.
    """
    if not args:
        return False

    # Extract parameters from args
    # Could be called as: can_distribute(a, min_slices) or can_distribute(n, k, a, min_slices)
    n = None
    k = None
    a = None
    min_slices = None

    for i, arg in enumerate(args):
        if isinstance(arg, (list, tuple)):
            a = arg
        elif isinstance(arg, int):
            if n is None:
                n = arg
            elif k is None:
                k = arg
            elif min_slices is None:
                min_slices = arg

    # Check kwargs for missing values
    if a is None:
        a = kwargs.get('a')
    if k is None:
        k = kwargs.get('k')
    if min_slices is None:
        min_slices = kwargs.get('min_slices')

    if a is None or min_slices is None:
        return False

    if min_slices <= 0:
        return False

    # If k is not provided, we just return True (can distribute to at least 1 pupil)
    if k is None:
        k = 1

    total_parts = 0
    for slices in a:
        total_parts += slices // min_slices

    return total_parts >= k

def count_slices(*args, **kwargs):
    """
    Calculate the total number of slices across all tangerines.
    """
    if not args:
        return 0
    # Extract a (the list of tangerine slices) from args
    a = None
    for arg in args:
        if isinstance(arg, (list, tuple)):
            a = arg
            break

    if a is None:
        return 0

    return sum(a)

def max_possible_joy(*args, **kwargs):
    """
    Find the maximum possible joy Santa can achieve by distributing tangerine slices to pupils.
    Uses binary search to determine the largest possible minimum number of slices each pupil can get.
    """
    if not args or len(args) < 3:
        return -1

    n = args[0]
    k = args[1]
    a = args[2]

    # Check if total slices is less than k (each pupil needs at least 1 slice)
    total_slices = sum(a)
    if total_slices < k:
        return -1

    # Binary search for the maximum possible joy
    left = 1
    right = max(a)
    result = -1

    while left <= right:
        mid = (left + right) // 2
        if can_distribute(n, k, a, mid):
            result = mid
            left = mid + 1
        else:
            right = mid - 1

    return result
